      // ----------------
      // OP_MSG FLAG BITS
      // ----------------
      0x00, 0x00, 0x01, 0x00, // OP_MSG flagBits (0x00010000 = exhaustAllowed bit set)
      // ---------------------
      // OP_MSG SECTIONS ARRAY
      // ---------------------
      0x00, // OP_MSG sections kind byte (0x00), indicating body is single BSON object
      // ------------------
      // SINGLE BSON OBJECT
      // ------------------
      0x77, 0x00, 0x00, 0x00,                                                                         // BSON object size (0x00000071 = 113) THIS HAS BEEN CHANGED TO 0x77
      0x10,                                                                                           // BSON element type (0x10 = int32)
      0x68, 0x65, 0x6c, 0x6c, 0x6f, 0x00,                                                             // BSON element cstring field name ("hello")
